import React, {type FC, useState} from "react";
import {Slider} from "primereact/slider";
import type { ISliderProps } from "@lmb-it/kitsconcerto-types";
import {Flex} from "../../../_compat";
import { useKitsTheme } from "../../../contexts/Theme";

const KitsSliders: FC<ISliderProps> = ({
  minValue = 0,
  maxValue = 100,
  prefix,
  orientation = "horizontal",
  value,
  isRange,
  onChange,
    required,
  onSlideEnd,
  className,
  ...props
}) => {
  const [localValue, setLocalValue] = useState<[number, number] | number>(
    isRange ? [minValue, minValue] : minValue,
  );

  const currentValue = onChange ? value : localValue;

  const { resolveToken } = useKitsTheme();
  const primaryColor = resolveToken('primary');

  return (
    <Flex
      flexDirection={"column"}
      gap={1}
      justifyContent={"center"}
      className="card"
      w={"full"}
    >
      <Slider
        className="w-full"
        value={currentValue}
        prefix={prefix}
        required={required}
        min={minValue}
        max={maxValue}
        orientation={orientation}
        onChange={(event) => {
          onChange ? onChange(event) : setLocalValue(event.value);
        }}
        onSlideEnd={onSlideEnd}
        range={isRange}
        pt={{
          range: {
            style: { backgroundColor: primaryColor },
          },
          handle: {
            style: { backgroundColor: primaryColor, borderColor: primaryColor },
          },
        }}
      />
      <Flex alignItems={"center"} justifyContent={"space-between"}>
        {isRange ? (
          <>
            <span>{Array.isArray(currentValue) ? currentValue[0] : minValue}</span>
            <span>{Array.isArray(currentValue) ? currentValue[1] : maxValue}</span>
          </>
        ) : (
          <span>{currentValue ? currentValue : 0}</span>
        )}
      </Flex>
    </Flex>
  );
};

export default KitsSliders;
